import unittest
from api import limit

class LimitTest(unittest.TestCase):
    def test_default(self): self.assertEqual(limit(), 10)
    def test_explicit(self): self.assertEqual(limit(7), 7)
    def test_malformed(self):
        with self.assertRaises(TypeError): limit('7')
